import{_ as t,o as e,c as r,a3 as o}from"./chunks/framework.q4B3G9ZH.js";const _=JSON.parse('{"title":"渲染管线","description":"","frontmatter":{},"headers":[],"relativePath":"图形学/渲染管线.md","filePath":"图形学/渲染管线.md","lastUpdated":null}'),n={name:"图形学/渲染管线.md"};function s(l,a,d,i,h,p){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="渲染管线" tabindex="-1">渲染管线 <a class="header-anchor" href="#渲染管线" aria-label="Permalink to &quot;渲染管线&quot;">​</a></h1><h2 id="顶点变换" tabindex="-1">顶点变换 <a class="header-anchor" href="#顶点变换" aria-label="Permalink to &quot;顶点变换&quot;">​</a></h2><h3 id="mvp变换" tabindex="-1">MVP变换 <a class="header-anchor" href="#mvp变换" aria-label="Permalink to &quot;MVP变换&quot;">​</a></h3><h4 id="世界变换-model" tabindex="-1">世界变换(Model) <a class="header-anchor" href="#世界变换-model" aria-label="Permalink to &quot;世界变换(Model)&quot;">​</a></h4><p>世界变换是指顶点从本地空间变换到世界空间的过程。</p><p>世界变换的顺序是<strong>缩放-&gt;旋转-&gt;平移</strong>。之所以必须是这个顺序：</p><p>在物体刚刚放入世界坐标系的时候使用的是本地坐标，也就是<strong>本地</strong>和<strong>全局坐标系</strong>的<strong>原点</strong>和<strong>坐标轴</strong>都是重合的，此时所有物体都把<strong>世界坐标系当做自己的本地坐标系</strong>。</p><p>而经过了坐标变换之后：</p><p>缩放变换不改变坐标轴的走向，也不改变原点的位置，所以两个坐标系仍然重合。</p><p>旋转变换改变坐标轴的走向，但不改变原点的位置，所以两个坐标系坐标轴不再处于相同走向。</p><p>平移变换不改变坐标轴走向，但改变原点位置，两个坐标系原点不再重合。</p><p>这样就可以解释为什么缩放不能在旋转之后，而缩放和旋转都不能在平移之后了。 于是没有问题的顺序只能是 缩放 -&gt; 旋转 -&gt; 平移 。</p><h4 id="视图变换" tabindex="-1">视图变换 <a class="header-anchor" href="#视图变换" aria-label="Permalink to &quot;视图变换&quot;">​</a></h4><h4 id="投影变换" tabindex="-1">投影变换 <a class="header-anchor" href="#投影变换" aria-label="Permalink to &quot;投影变换&quot;">​</a></h4>',14)])])}const m=t(n,[["render",s]]);export{_ as __pageData,m as default};
